content.content:
   1→<div class="overview">
   2→  <.card
   3→    title={dgettext("dashboard_projects", "Analytics")}
   4→    icon="chart_arcs"
   5→    data-part="analytics"
   6→  >
   7→    <:actions>
   8→      <.dropdown
   9→        id="overview-analytics-environment-dropdown"
  10→        label={@analytics_environment_label}
  11→        secondary_text={dgettext("dashboard_projects", "Environment:")}
  12→      >
  13→        <.dropdown_item
  14→          value="any"
  15→          label={dgettext("dashboard_projects", "Any")}
  16→          patch={"?#{Query.put(@uri.query, "analytics-environment", "any")}"}
  17→          data-selected={@analytics_environment == "any"}
  18→        >
  19→          <:right_icon><.check /></:right_icon>
  20→        </.dropdown_item>
  21→        <.dropdown_item
  22→          value="local"
  23→          label={dgettext("dashboard_projects", "Local")}
  24→          patch={"?#{Query.put(@uri.query, "analytics-environment", "local")}"}
  25→          data-selected={@analytics_environment == "local"}
  26→        >
  27→          <:right_icon><.check /></:right_icon>
  28→        </.dropdown_item>
  29→        <.dropdown_item
  30→          value="ci"
  31→          label={dgettext("dashboard_projects", "CI")}
  32→          patch={"?#{Query.put(@uri.query, "analytics-environment", "ci")}"}
  33→          data-selected={@analytics_environment == "ci"}
  34→        >
  35→          <:right_icon><.check /></:right_icon>
  36→        </.dropdown_item>
  37→      </.dropdown>
  38→      <.date_picker
  39→        id="analytics-date-range-picker"
  40→        name="analytics-date-range"
  41→        presets={[
  42→          %{
  43→            id: "last-24-hours",
  44→            label: dgettext("dashboard_projects", "Last 24 hours"),
  45→            period: {24, :hour}
  46→          },
  47→          %{
  48→            id: "last-7-days",
  49→            label: dgettext("dashboard_projects", "Last 7 days"),
  50→            period: {7, :day}
  51→          },
  52→          %{
  53→            id: "last-30-days",
  54→            label: dgettext("dashboard_projects", "Last 30 days"),
  55→            period: {30, :day}
  56→          },
  57→          %{
  58→            id: "last-12-months",
  59→            label: dgettext("dashboard_projects", "Last 12 months"),
  60→            period: {12, :month}
  61→          },
  62→          %{id: "custom", label: dgettext("dashboard_projects", "Custom")}
  63→        ]}
  64→        selected_preset={@analytics_preset}
  65→        period={@analytics_period}
  66→        on_period_change="analytics_period_changed"
  67→        max={Date.utc_today()}
  68→      >
  69→        <:actions>
  70→          <.button
  71→            label={dgettext("dashboard_projects", "Cancel")}
  72→            variant="secondary"
  73→            phx-click={
  74→              JS.dispatch("phx:date-picker-cancel",
  75→                detail: %{id: "analytics-date-range-picker"}
  76→              )
  77→            }
  78→          />
  79→          <.button
  80→            label={dgettext("dashboard_projects", "Apply")}
  81→            phx-click={
  82→              JS.dispatch("phx:date-picker-apply", detail: %{id: "analytics-date-range-picker"})
  83→            }
  84→          />
  85→        </:actions>
  86→      </.date_picker>
  87→    </:actions>
  88→    <div data-part="analytics-content">
  89→      <div data-part="widgets">
  90→        <.widget
  91→          loading={!@binary_cache_hit_rate_analytics.ok?}
  92→          title={dgettext("dashboard_projects", "Cache effectiveness")}
  93→          description={
  94→            dgettext(
  95→              "dashboard_projects",
  96→              "Cache effectiveness represents the combined hit rate of both Module cache and Xcode cache, showing the percentage of cacheable items that were resolved from cache rather than being rebuilt."
  97→            )
  98→          }
  99→          value={
 100→            if @binary_cache_hit_rate_analytics.ok?,
 101→              do:
 102→                dgettext("dashboard_projects", "%{binary_cache_effectiveness}%",
 103→                  binary_cache_effectiveness:
 104→                    (@binary_cache_hit_rate_analytics.result.cache_hit_rate * 100)
 105→                    |> Decimal.from_float()
 106→                    |> Decimal.round(1)
 107→                )
 108→          }
 109→          id="widget-binary-cache-effectiveness"
 110→          trend_value={
 111→            if @binary_cache_hit_rate_analytics.ok?,
 112→              do: @binary_cache_hit_rate_analytics.result.trend,
 113→              else: nil
 114→          }
 115→          trend_label={@analytics_trend_label}
 116→          empty={
 117→            @binary_cache_hit_rate_analytics.ok? &&
 118→              @binary_cache_hit_rate_analytics.result.cache_hit_rate == 0.0
 119→          }
 120→        />
 121→        <.widget
 122→          loading={!@selective_testing_analytics.ok?}
 123→          title={dgettext("dashboard_projects", "Selective test effectiveness")}
 124→          description={
 125→            dgettext(
 126→              "dashboard_projects",
 127→              "Selective test effectiveness represents the ratio of selective test hits compared to selective test misses."
 128→            )
 129→          }
 130→          value={
 131→            if @selective_testing_analytics.ok?,
 132→              do:
 133→                dgettext("dashboard_projects", "%{selective_tests_effectiveness}%",
 134→                  selective_tests_effectiveness:
 135→                    (@selective_testing_analytics.result.hit_rate * 100)
 136→                    |> Decimal.from_float()
 137→                    |> Decimal.round(1)
 138→                )
 139→          }
 140→          id="widget-selective-tests-effectiveness"
 141→          trend_value={
 142→            if @selective_testing_analytics.ok?,
 143→              do: @selective_testing_analytics.result.trend,
 144→              else: nil
 145→          }
 146→          trend_label={@analytics_trend_label}
 147→          empty={
 148→            @selective_testing_analytics.ok? &&
 149→              @selective_testing_analytics.result.hit_rate == 0.0
 150→          }
 151→        />
 152→        <.widget
 153→          loading={!@build_analytics.ok?}
 154→          title={dgettext("dashboard_projects", "Average build time")}
 155→          description={
 156→            dgettext(
 157→              "dashboard_projects",
 158→              "Average time it takes to build a project as reported from Xcode post actions."
 159→            )
 160→          }
 161→          value={
 162→            if @build_analytics.ok?,
 163→              do:
 164→                dgettext("dashboard_projects", "%{duration}s",
 165→                  duration: Float.round(@build_analytics.result.total_average_duration / 1000, 1)
 166→                )
 167→          }
 168→          id="widget-average-build-time"
 169→          trend_value={if @build_analytics.ok?, do: @build_analytics.result.trend, else: nil}
 170→          trend_label={@analytics_trend_label}
 171→          trend_type={:inverse}
 172→          empty={@build_analytics.ok? && @build_analytics.result.total_average_duration == 0}
 173→        />
 174→        <.widget
 175→          loading={!@test_analytics.ok?}
 176→          title={dgettext("dashboard_projects", "Average test time")}
 177→          description={
 178→            dgettext(
 179→              "dashboard_projects",
 180→              "Average time it takes to test a project when using the 'tuist test' command."
 181→            )
 182→          }
 183→          value={
 184→            if @test_analytics.ok?,
 185→              do:
 186→                dgettext("dashboard_projects", "%{duration}s",
 187→                  duration: Float.round(@test_analytics.result.total_average_duration / 1000, 1)
 188→                )
 189→          }
 190→          id="widget-average-test-time"
 191→          trend_value={if @test_analytics.ok?, do: @test_analytics.result.trend, else: nil}
 192→          trend_label={@analytics_trend_label}
 193→          trend_type={:inverse}
 194→          empty={@test_analytics.ok? && @test_analytics.result.total_average_duration == 0}
 195→        />
 196→      </div>
 197→      <div
 198→        :if={
 199→          !@binary_cache_hit_rate_analytics.ok? ||
 200→            @binary_cache_hit_rate_analytics.result.cache_hit_rate != 0.0
 201→        }
 202→        data-part="cache-cards-section"
 203→      >
 204→        <.card_section
 205→          :if={!@binary_cache_hit_rate_analytics.ok? || !@selective_testing_analytics.ok?}
 206→          data-part="cache-effectiveness-card-chart-section"
 207→        >
 208→          <div data-part="effectiveness-chart">
 209→            <div data-part="legends">
 210→              <.skeleton_legend />
 211→              <.skeleton_legend />
 212→            </div>
 213→            <.skeleton_chart />
 214→          </div>
 215→        </.card_section>
 216→        <.card_section
 217→          :if={
 218→            @binary_cache_hit_rate_analytics.ok? &&
 219→              @selective_testing_analytics.ok? &&
 220→              @binary_cache_hit_rate_analytics.result.cache_hit_rate != 0.0
 221→          }
 222→          data-part="cache-effectiveness-card-chart-section"
 223→        >
 224→          <div data-part="effectiveness-chart">
 225→            <div data-part="legends">
 226→              <.legend
 227→                title={dgettext("dashboard_projects", "Cache effectiveness")}
 228→                value={
 229→                  dgettext("dashboard_projects", "%{binary_cache_effectiveness}%",
 230→                    binary_cache_effectiveness:
 231→                      (@binary_cache_hit_rate_analytics.result.cache_hit_rate * 100)
 232→                      |> Decimal.from_float()
 233→                      |> Decimal.round(1)
 234→                  )
 235→                }
 236→                style="primary"
 237→              />
 238→              <.legend
 239→                title={dgettext("dashboard_projects", "Selective test effectiveness")}
 240→                value={
 241→                  dgettext("dashboard_projects", "%{selective_test_effectiveness}%",
 242→                    selective_test_effectiveness:
 243→                      (@selective_testing_analytics.result.hit_rate * 100)
 244→                      |> Decimal.from_float()
 245→                      |> Decimal.round(1)
 246→                  )
 247→                }
 248→                style="secondary"
 249→              />
 250→            </div>
 251→            <.chart
 252→              id="chart-single-multi-series-line"
 253→              type="line"
 254→              extra_options={
 255→                %{
 256→                  grid: %{
 257→                    width: "93%",
 258→                    left: "0%",
 259→                    right: "7%",
 260→                    height: "88%",
 261→                    top: "5%"
 262→                  },
 263→                  xAxis: %{
 264→                    boundaryGap: false,
 265→                    type: "category",
 266→                    axisLabel: %{
 267→                      color: "var:noora-surface-label-secondary",
 268→                      formatter: "fn:toLocaleDate",
 269→                      customValues: [
 270→                        @binary_cache_hit_rate_analytics.result.dates |> hd(),
 271→                        @binary_cache_hit_rate_analytics.result.dates |> List.last()
 272→                      ],
 273→                      padding: [10, 0, 0, 0]
 274→                    }
 275→                  },
 276→                  yAxis: %{
 277→                    splitLine: %{
 278→                      lineStyle: %{
 279→                        color: "var:noora-chart-lines"
 280→                      }
 281→                    },
 282→                    axisLabel: %{
 283→                      color: "var:noora-surface-label-secondary",
 284→                      formatter: "{value}%"
 285→                    }
 286→                  },
 287→                  tooltip:
 288→                    if @analytics_preset == "last-24-hours" do
 289→                      %{valueFormat: "{value}%", dateFormat: "hour"}
 290→                    else
 291→                      %{valueFormat: "{value}%"}
 292→                    end,
 293→                  legend: %{
 294→                    show: false
 295→                  }
 296→                }
 297→              }
 298→              series={[
 299→                %{
 300→                  data:
 301→                    Enum.zip(
 302→                      @binary_cache_hit_rate_analytics.result.dates,
 303→                      @binary_cache_hit_rate_analytics.result.values
 304→                      |> Enum.map(&(&1 * 100))
 305→                      |> Enum.map(&Decimal.from_float/1)
 306→                      |> Enum.map(&Decimal.round(&1, 1))
 307→                    )
 308→                    |> Enum.map(&Tuple.to_list/1),
 309→                  name: dgettext("dashboard_projects", "Cache effectiveness"),
 310→                  type: "line",
 311→                  smooth: 0.1,
 312→                  symbol: "none"
 313→                },
 314→                %{
 315→                  data:
 316→                    Enum.zip(
 317→                      @selective_testing_analytics.result.dates,
 318→                      @selective_testing_analytics.result.values
 319→                      |> Enum.map(&(&1 * 100))
 320→                      |> Enum.map(&Decimal.from_float/1)
 321→                      |> Enum.map(&Decimal.round(&1, 1))
 322→                    )
 323→                    |> Enum.map(&Tuple.to_list/1),
 324→                  name: dgettext("dashboard_projects", "Selective test effectiveness"),
 325→                  type: "line",
 326→                  smooth: 0.1,
 327→                  symbol: "none"
 328→                }
 329→              ]}
 330→              y_axis_min={0}
 331→              y_axis_max={100}
 332→            />
 333→          </div>
 334→        </.card_section>
 335→        <.card_section
 336→          :if={
 337→            @build_time_analytics.ok? &&
 338→              @analytics_environment == "ci" &&
 339→              @build_time_analytics.result.total_time_saved != 0 &&
 340→              @build_time_analytics.result.total_build_time != 0
 341→          }
 342→          data-part="time-saved-card-chart-section"
 343→        >
 344→          <div data-part="legends">
 345→            <.legend
 346→              title={dgettext("dashboard_projects", "Build time saved")}
 347→              value={
 348→                Tuist.Utilities.DateFormatter.format_duration_from_milliseconds(
 349→                  @build_time_analytics.result.total_time_saved,
 350→                  include_seconds: false
 351→                )
 352→              }
 353→              style="primary"
 354→            />
 355→          </div>
 356→          <.chart
 357→            id="time-saved-segmented-chart"
 358→            type="bar"
 359→            style="height: 100px"
 360→            extra_options={
 361→              %{
 362→                grid: %{
 363→                  left: "5%",
 364→                  right: "50px",
 365→                  top: "15px",
 366→                  bottom: "15px"
 367→                },
 368→                xAxis: %{
 369→                  type: "value",
 370→                  axisLabel: %{
 371→                    color: "var:noora-surface-label-secondary",
 372→                    formatter:
 373→                      if(@build_time_analytics.result.total_build_time < 3_600_000,
 374→                        do: "fn:formatSeconds",
 375→                        else: "fn:formatHours"
 376→                      ),
 377→                    hideOverlap: true
 378→                  },
 379→                  axisTick: %{show: false}
 380→                },
 381→                yAxis: %{
 382→                  type: "category",
 383→                  data: [dgettext("dashboard_projects", "Build time")],
 384→                  axisLabel: %{
 385→                    color: "var:noora-surface-label-secondary"
 386→                  },
 387→                  axisLine: %{show: false},
 388→                  axisTick: %{show: false},
 389→                  splitLine: %{
 390→                    lineStyle: %{
 391→                      color: "var:noora-chart-lines"
 392→                    }
 393→                  }
 394→                },
 395→                legend: %{show: false},
 396→                tooltip: %{
 397→                  trigger: "axis",
 398→                  axisPointer: %{type: "none"},
 399→                  valueFormat:
 400→                    if(@build_time_analytics.result.total_build_time < 3_600_000,
 401→                      do: "fn:formatSeconds",
 402→                      else: "fn:formatHours"
 403→                    )
 404→                }
 405→              }
 406→            }
 407→            series={[
 408→              %{
 409→                name: dgettext("dashboard_projects", "Saved"),
 410→                type: "bar",
 411→                stack: "total",
 412→                itemStyle: %{
 413→                  color: "var:noora-chart-legend-primary",
 414→                  borderRadius: [0, 4, 4, 0]
 415→                },
 416→                data: [
 417→                  if(@build_time_analytics.result.total_build_time < 3_600_000,
 418→                    do:
 419→                      (@build_time_analytics.result.total_time_saved / 1000)
 420→                      |> Decimal.from_float()
 421→                      |> Decimal.round(1),
 422→                    else:
 423→                      (@build_time_analytics.result.total_time_saved / 3_600_000)
 424→                      |> Decimal.from_float()
 425→                      |> Decimal.round(2)
 426→                  )
 427→                ]
 428→              }
 429→            ]}
 430→            x_axis_min={0}
 431→          />
 432→        </.card_section>
 433→      </div>
 434→      <.empty_card_section
 435→        :if={
 436→          @binary_cache_hit_rate_analytics.ok? &&
 437→            @binary_cache_hit_rate_analytics.result.cache_hit_rate == 0.0
 438→        }
 439→        title={dgettext("dashboard_projects", "Binary cache and selective testing: no data yet")}
 440→        get_started_href="https://docs.tuist.dev/en/"
 441→      >
 442→        <:image>
 443→          <img src="/images/empty_line_chart_light.png" data-theme="light" />
 444→          <img src="/images/empty_line_chart_dark.png" data-theme="dark" />
 445→        </:image>
 446→      </.empty_card_section>
 447→    </div>
 448→  </.card>
 449→  <.card title={dgettext("dashboard_projects", "Tests")} icon="subtask">
 450→    <:actions>
 451→      <.button
 452→        variant="secondary"
 453→        label={dgettext("dashboard_projects", "View more")}
 454→        size="medium"
 455→        navigate={~p"/#{@selected_account.name}/#{@selected_project.name}/tests/test-runs"}
 456→        disabled={!@recent_test_runs.ok? || Enum.empty?(@recent_test_runs.result)}
 457→      />
 458→    </:actions>
 459→    <.card_section :if={!@recent_test_runs.ok?}>
 460→      <div data-part="test-runs-chart">
 461→        <div data-part="legends">
 462→          <.skeleton_legend />
 463→          <.skeleton_legend />
 464→        </div>
 465→        <.skeleton_chart />
 466→      </div>
 467→    </.card_section>
 468→    <.card_section :if={@recent_test_runs.ok? && not Enum.empty?(@recent_test_runs.result)}>
 469→      <div data-part="test-runs-chart">
 470→        <div data-part="legends">
 471→          <.legend
 472→            title={dgettext("dashboard_projects", "Passed runs")}
 473→            value={@passed_test_runs_count.result}
 474→            style="primary"
 475→          />
 476→          <.legend
 477→            title={dgettext("dashboard_projects", "Failed runs")}
 478→            value={@failed_test_runs_count.result}
 479→            style="destructive"
 480→          />
 481→        </div>
 482→        <.chart
 483→          id="chart-single-test-run-duration"
 484→          type="bar"
 485→          extra_options={
 486→            %{
 487→              grid: %{
 488→                width: "93%",
 489→                left: "0.4%",
 490→                right: "7%",
 491→                height: "88%",
 492→                top: "5%"
 493→              },
 494→              tooltip: %{
 495→                valueFormat: "fn:formatSeconds",
 496→                dateFormat: "minute"
 497→              },
 498→              xAxis: %{
 499→                axisLabel: %{show: false},
 500→                data: @recent_test_runs.result |> Enum.map(& &1.date)
 501→              },
 502→              yAxis: %{
 503→                splitLine: %{
 504→                  lineStyle: %{
 505→                    color: "var:noora-chart-lines"
 506→                  }
 507→                },
 508→                axisLabel: %{
 509→                  color: "var:noora-surface-label-secondary",
 510→                  formatter: "fn:formatSeconds"
 511→                }
 512→              },
 513→              legend: %{
 514→                show: false
 515→              }
 516→            }
 517→          }
 518→          series={[
 519→            %{
 520→              data: @recent_test_runs.result,
 521→              name: "Test Run",
 522→              type: "bar"
 523→            }
 524→          ]}
 525→          y_axis_min={0}
 526→          grid_lines
 527→          bar_width={8}
 528→          bar_radius={2}
 529→        />
 530→        <span data-part="label">{dgettext("dashboard_projects", "Last 40 runs")}</span>
 531→      </div>
 532→    </.card_section>
 533→    <.empty_card_section
 534→      :if={@recent_test_runs.ok? && Enum.empty?(@recent_test_runs.result)}
 535→      title={dgettext("dashboard_projects", "Runs: no data yet")}
 536→      get_started_href="https://docs.tuist.dev/en/guides/develop/selective-testing"
 537→    >
 538→      <:image>
 539→        <img src="/images/empty_bar_chart_light.png" data-theme="light" />
 540→        <img src="/images/empty_bar_chart_dark.png" data-theme="dark" />
 541→      </:image>
 542→    </.empty_card_section>
 543→  </.card>
 544→  <.card title={dgettext("dashboard_projects", "Previews")} icon="devices" data-part="previews">
 545→    <:actions>
 546→      <.button
 547→        variant="secondary"
 548→        label={dgettext("dashboard_projects", "View more")}
 549→        size="medium"
 550→        navigate={~p"/#{@selected_account.name}/#{@selected_project.name}/previews"}
 551→        disabled={!@latest_app_previews.ok? || Enum.empty?(@latest_app_previews.result)}
 552→      />
 553→    </:actions>
 554→    <.card_section :if={!@latest_app_previews.ok?} data-part="latest-app-previews">
 555→      <span data-part="title" class="tuist-loading-skeleton">
 556→        &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
 557→      </span>
 558→      <div data-part="apps">
 559→        <.skeleton_box
 560→          :for={_ <- 1..3}
 561→          width="64px"
 562→          height="64px"
 563→          border_radius="var(--noora-radius-large)"
 564→        />
 565→      </div>
 566→    </.card_section>
 567→    <.card_section
 568→      :if={@latest_app_previews.ok? && not Enum.empty?(@latest_app_previews.result)}
 569→      data-part="latest-app-previews"
 570→    >
 571→      <span data-part="title">{dgettext("dashboard_projects", "Latest app previews")}</span>
 572→      <div data-part="apps">
 573→        <%= for preview <- @latest_app_previews.result do %>
 574→          <.app_preview preview={preview} user_agent={@user_agent} />
 575→        <% end %>
 576→      </div>
 577→    </.card_section>
 578→    <.empty_card_section
 579→      :if={@latest_app_previews.ok? && Enum.empty?(@latest_app_previews.result)}
 580→      data-part="empty-previews-card-section"
 581→      title={dgettext("dashboard_projects", "No previews yet")}
 582→      get_started_href="https://docs.tuist.dev/en/guides/features/previews"
 583→    >
 584→      <:image>
 585→        <img src="/images/empty_previews_light.png" data-theme="light" />
 586→        <img src="/images/empty_previews_dark.png" data-theme="dark" />
 587→      </:image>
 588→    </.empty_card_section>
 589→  </.card>
 590→  <.card
 591→    title={dgettext("dashboard_projects", "Bundles")}
 592→    icon="chart_donut_4"
 593→    data-part="bundle-size-card"
 594→  >
 595→    <:actions>
 596→      <.dropdown
 597→        id="bundle-size-app-dropdown"
 598→        label={@bundle_size_selected_app}
 599→        secondary_text={dgettext("dashboard_projects", "App:")}
 600→      >
 601→        <.dropdown_item
 602→          :for={app <- if(@bundle_size_apps.ok?, do: @bundle_size_apps.result, else: [])}
 603→          value={app}
 604→          label={app}
 605→          patch={"?#{Query.put(@uri.query, "bundle-size-app", app)}"}
 606→          data-selected={@bundle_size_selected_app == app}
 607→        >
 608→          <:right_icon><.check /></:right_icon>
 609→        </.dropdown_item>
 610→      </.dropdown>
 611→      <.date_picker
 612→        id="bundle-size-date-range-picker"
 613→        name="bundle-size-date-range"
 614→        presets={[
 615→          %{
 616→            id: "last-7-days",
 617→            label: dgettext("dashboard_projects", "Last 7 days"),
